import { useState, useRef } from 'react'

const MAX_FILE_SIZE = 5 * 1024 * 1024 // 5MB absolute max
const COMPRESS_THRESHOLD = 400 * 1024 // 400KB

export default function ImageUpload({ images, setImages, maxImages = 3 }) {
    const [uploadingIndex, setUploadingIndex] = useState(null)
    const fileInputRef = useRef(null)
    const [activeIndex, setActiveIndex] = useState(null)

    const compressImage = (file) => {
        return new Promise((resolve, reject) => {
            const reader = new FileReader()
            reader.readAsDataURL(file)
            reader.onload = (event) => {
                const img = new Image()
                img.src = event.target.result
                img.onload = () => {
                    const canvas = document.createElement('canvas')
                    let { width, height } = img
                    const maxDim = 1200

                    if (width > height && width > maxDim) {
                        height = Math.round((height * maxDim) / width)
                        width = maxDim
                    } else if (height > width && height > maxDim) {
                        width = Math.round((width * maxDim) / height)
                        height = maxDim
                    }

                    canvas.width = width
                    canvas.height = height
                    const ctx = canvas.getContext('2d')
                    ctx.drawImage(img, 0, 0, width, height)

                    canvas.toBlob((blob) => {
                        if (!blob) {
                            resolve(file) // fallback to original
                            return
                        }
                        const compressedFile = new File([blob], file.name.replace(/\.[^/.]+$/, "") + ".jpg", {
                            type: 'image/jpeg',
                            lastModified: Date.now()
                        })
                        resolve(compressedFile)
                    }, 'image/jpeg', 0.7)
                }
                img.onerror = () => resolve(file)
            }
            reader.onerror = () => resolve(file)
        })
    }

    const handleFiles = async (file) => {
        if (!file) return

        if (!file.type.startsWith('image/')) {
            alert('Please select an image file.')
            return
        }
        if (file.size > MAX_FILE_SIZE) {
            alert('Image must be under 5MB before compression.')
            return
        }

        setUploadingIndex(activeIndex)

        try {
            let finalFile = file;
            // Compress if over 400KB
            if (file.size > COMPRESS_THRESHOLD) {
                finalFile = await compressImage(file)
            }

            const previewUrl = URL.createObjectURL(finalFile)

            const newImages = [...images]
            while (newImages.length < maxImages) newImages.push(null)

            newImages[activeIndex] = { file: finalFile, previewUrl }

            // Clean up any nulls before passing to parent
            setImages(newImages.filter(item => item !== null))
        } catch (err) {
            console.error('Error processing image:', err)
            alert('Failed to process image.')
        } finally {
            setUploadingIndex(null)
            setActiveIndex(null)
            if (fileInputRef.current) fileInputRef.current.value = ''
        }
    }

    const removeImage = (indexToRemove) => {
        const newImages = [...images]

        // Revoke the object URL to avoid memory leaks
        const img = newImages[indexToRemove]
        if (img && img.previewUrl) {
            URL.revokeObjectURL(img.previewUrl)
        }

        newImages.splice(indexToRemove, 1)
        setImages(newImages)
    }

    const handleBoxClick = (index) => {
        setActiveIndex(index)
        fileInputRef.current?.click()
    }

    // Helper to get image preview url at index safely
    const getImageUrl = (index) => images[index]?.previewUrl || null

    return (
        <div className="image-upload-boxes">
            {Array.from({ length: maxImages }).map((_, index) => {
                const url = getImageUrl(index)
                const isUploading = uploadingIndex === index

                return (
                    <div
                        key={index}
                        className={`upload-box ${url ? 'has-image' : ''}`}
                        onClick={() => !url && !isUploading && handleBoxClick(index)}
                    >
                        {isUploading ? (
                            <div className="upload-loading">
                                <div className="spinner small"></div>
                            </div>
                        ) : url ? (
                            <>
                                <img src={url} alt={`Upload ${index + 1}`} />
                                <button
                                    className="image-remove"
                                    onClick={(e) => { e.stopPropagation(); removeImage(index); }}
                                    type="button"
                                >
                                    ×
                                </button>
                            </>
                        ) : (
                            <div className="upload-placeholder">
                                <span className="plus-icon">+</span>
                                <span className="box-label">Photo {index + 1}</span>
                            </div>
                        )}
                    </div>
                )
            })}

            <input
                ref={fileInputRef}
                type="file"
                accept="image/*"
                onChange={(e) => handleFiles(e.target.files[0])}
                style={{ display: 'none' }}
            />
        </div>
    )
}

import { createContext, useContext, useEffect, useRef, useState } from 'react'
import { supabase } from '../lib/supabase'

const AuthContext = createContext({})

export const useAuth = () => useContext(AuthContext)

const AUTH_SESSION_TIMEOUT_MS = 8000

export function AuthProvider({ children }) {
    const [user, setUser] = useState(null)
    const [profile, setProfile] = useState(null)
    const [loading, setLoading] = useState(true)
    const [profileLoading, setProfileLoading] = useState(false)
    const mountedRef = useRef(false)

    useEffect(() => {
        mountedRef.current = true
        let subscription = null

        const initSession = async () => {
            let timeoutId = null
            let didTimeout = false

            timeoutId = setTimeout(() => {
                didTimeout = true
                if (!mountedRef.current) return
                console.warn('Auth session lookup is slow; continuing without blocking UI.')
                setLoading(false)
            }, AUTH_SESSION_TIMEOUT_MS)

            try {
                const { data, error } = await supabase.auth.getSession()

                if (timeoutId) clearTimeout(timeoutId)
                if (!mountedRef.current) return

                if (error) {
                    throw error
                }

                const session = data?.session
                setUser(session?.user ?? null)
                setLoading(false)

                if (session?.user) {
                    fetchProfile(session.user.id)
                } else {
                    setProfile(null)
                }
            } catch (err) {
                if (timeoutId) clearTimeout(timeoutId)
                if (didTimeout) {
                    return
                }
                console.error('Session error:', err)
                if (!mountedRef.current) return
                setUser(null)
                setProfile(null)
                setLoading(false)
            }
        }

        initSession()

        const setupAuthListener = () => {
            const { data } = supabase.auth.onAuthStateChange(
                (_event, session) => {
                    if (!mountedRef.current) return
                    setUser(session?.user ?? null)
                    setLoading(false)
                    if (session?.user) {
                        fetchProfile(session.user.id)
                    } else {
                        setProfile(null)
                    }
                }
            )
            subscription = data.subscription
        }

        setupAuthListener()

        return () => {
            mountedRef.current = false
            if (subscription) {
                subscription.unsubscribe()
            }
        }
    }, [])

    async function fetchProfile(userId) {
        if (!userId) return
        setProfileLoading(true)
        try {
            const { data, error } = await supabase
                .from('profiles')
                .select('*')
                .eq('id', userId)
                .single()

            if (error && error.code === 'PGRST116') {
                // Profile doesn't exist yet, create it
                const { data: userData, error: userError } = await supabase.auth.getUser()
                if (userError) throw userError
                const meta = userData?.user?.user_metadata
                const { data: newProfile, error: insertError } = await supabase
                    .from('profiles')
                    .insert({
                        id: userId,
                        full_name: meta?.full_name || meta?.name || '',
                        avatar_url: meta?.avatar_url || meta?.picture || '',
                    })
                    .select()
                    .single()
                if (insertError) throw insertError
                if (mountedRef.current) setProfile(newProfile)
            } else if (error) {
                throw error
            } else if (mountedRef.current) {
                setProfile(data)
            }
        } catch (err) {
            console.error('Error fetching profile:', err)
            if (mountedRef.current) setProfile(null)
        } finally {
            if (mountedRef.current) setProfileLoading(false)
        }
    }

    async function signInWithGoogle() {
        const { error } = await supabase.auth.signInWithOAuth({
            provider: 'google',
            options: {
                redirectTo: window.location.origin,
            },
        })
        if (error) console.error('Error signing in:', error)
    }

    async function signOut() {
        const { error } = await supabase.auth.signOut()
        if (error) console.error('Error signing out:', error)
    }

    async function updateProfile(updates) {
        const { data, error } = await supabase
            .from('profiles')
            .update(updates)
            .eq('id', user.id)
            .select()
            .single()
        if (error) throw error
        setProfile(data)
        return data
    }

    const value = {
        user,
        profile,
        loading,
        profileLoading,
        signInWithGoogle,
        signOut,
        updateProfile,
        fetchProfile,
    }

    return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>
}

import { useState, useEffect } from 'react'
import { useParams, useNavigate } from 'react-router-dom'
import { supabase } from '../lib/supabase'
import { useAuth } from '../context/AuthContext'
import ImageUpload from '../components/ImageUpload'

const CATEGORIES = ['Books', 'Electronics', 'Clothing', 'Furniture', 'Stationery', 'Sports', 'Other']

export default function EditListing() {
    const { id } = useParams()
    const { user } = useAuth()
    const navigate = useNavigate()
    const [loading, setLoading] = useState(true)
    const [saving, setSaving] = useState(false)
    const [images, setImages] = useState([])
    const [originalImages, setOriginalImages] = useState([])
    const [form, setForm] = useState({
        name: '',
        price: '',
        description: '',
        category: '',
    })

    useEffect(() => {
        fetchProduct()
    }, [id])

    async function fetchProduct() {
        try {
            const { data, error } = await supabase
                .from('products')
                .select('*')
                .eq('id', id)
                .single()

            if (error) throw error

            if (data.user_id !== user.id) {
                navigate('/')
                return
            }

            setForm({
                name: data.name || '',
                price: data.price?.toString() || '',
                description: data.description || '',
                category: data.category || '',
            })

            // Format existing images for ImageUpload component
            const existingImages = data.images || []
            setOriginalImages(existingImages)

            const formattedImages = existingImages.map(url => ({
                file: null, // No local file for existing images
                previewUrl: url
            }))
            setImages(formattedImages)
        } catch (err) {
            console.error('Error fetching product:', err)
            navigate('/')
        } finally {
            setLoading(false)
        }
    }

    const handleChange = (e) => {
        setForm({ ...form, [e.target.name]: e.target.value })
    }

    const handleSubmit = async (e) => {
        e.preventDefault()

        if (!form.name.trim() || !form.price || !form.category) {
            alert('Please fill in all required fields')
            return
        }

        setSaving(true)
        try {
            // 1. Process images
            const finalUrls = []

            for (const img of images) {
                if (!img) continue

                if (img.file) {
                    // This is a new image, upload it
                    const ext = img.file.name.split('.').pop()
                    const fileName = `${Date.now()}-${Math.random().toString(36).substr(2, 9)}.${ext}`
                    const filePath = `listings/${fileName}`

                    const { error: uploadError } = await supabase.storage
                        .from('product-images')
                        .upload(filePath, img.file)

                    if (uploadError) throw new Error('Failed to upload new image.')

                    const { data: { publicUrl } } = supabase.storage
                        .from('product-images')
                        .getPublicUrl(filePath)

                    finalUrls.push(publicUrl)
                } else if (img.previewUrl) {
                    // This is an existing image we are keeping
                    finalUrls.push(img.previewUrl)
                }
            }

            // 2. Cleanup replaced/deleted old images from storage
            const pathsToRemove = originalImages
                .filter(url => !finalUrls.includes(url))
                .map(url => {
                    const parts = url.split('product-images/')
                    return parts.length > 1 ? parts[1] : null
                })
                .filter(Boolean)

            if (pathsToRemove.length > 0) {
                const { error: storageError } = await supabase.storage
                    .from('product-images')
                    .remove(pathsToRemove)
                if (storageError) console.error('Error removing old images:', storageError)
            }

            // 3. Update database
            const { error } = await supabase
                .from('products')
                .update({
                    name: form.name.trim(),
                    price: parseFloat(form.price),
                    description: form.description.trim(),
                    category: form.category,
                    images: finalUrls,
                })
                .eq('id', id)

            if (error) throw error
            navigate(`/product/${id}`)
        } catch (err) {
            console.error('Error updating listing:', err)
            alert('Failed to update listing. Please try again.')
        } finally {
            // Memory cleanup for local previews
            images.forEach(img => {
                if (img && img.file && img.previewUrl) {
                    URL.revokeObjectURL(img.previewUrl)
                }
            })
            setSaving(false)
        }
    }

    if (loading) {
        return (
            <div className="loading-screen">
                <div className="spinner"></div>
                <p>Loading listing...</p>
            </div>
        )
    }

    return (
        <div className="create-listing-page">
            <div className="page-header">
                <h1>Edit Listing</h1>
                <p>Update your product details</p>
            </div>

            <form onSubmit={handleSubmit} className="listing-form">
                <div className="form-group">
                    <label htmlFor="name">Product Name *</label>
                    <input
                        id="name"
                        name="name"
                        type="text"
                        placeholder="e.g., Engineering Mathematics Textbook"
                        value={form.name}
                        onChange={handleChange}
                        required
                    />
                </div>

                <div className="form-row">
                    <div className="form-group">
                        <label htmlFor="price">Price (₹) *</label>
                        <input
                            id="price"
                            name="price"
                            type="number"
                            min="0"
                            step="1"
                            placeholder="500"
                            value={form.price}
                            onChange={handleChange}
                            required
                        />
                    </div>

                    <div className="form-group">
                        <label htmlFor="category">Category *</label>
                        <select
                            id="category"
                            name="category"
                            value={form.category}
                            onChange={handleChange}
                            required
                        >
                            <option value="">Select category</option>
                            {CATEGORIES.map((cat) => (
                                <option key={cat} value={cat}>{cat}</option>
                            ))}
                        </select>
                    </div>
                </div>

                <div className="form-group">
                    <label htmlFor="description">Description</label>
                    <textarea
                        id="description"
                        name="description"
                        rows={4}
                        placeholder="Describe your item — condition, reason for selling, etc."
                        value={form.description}
                        onChange={handleChange}
                    />
                </div>

                <div className="form-group">
                    <label>Photos (max 3)</label>
                    <ImageUpload images={images} setImages={setImages} maxImages={3} />
                </div>

                <div className="form-actions-row">
                    <button
                        type="button"
                        className="btn btn-secondary btn-lg"
                        onClick={() => navigate(`/product/${id}`)}
                    >
                        Cancel
                    </button>
                    <button
                        type="submit"
                        className="btn btn-primary btn-lg"
                        disabled={saving}
                    >
                        {saving ? (
                            <>
                                <div className="spinner small"></div>
                                Saving...
                            </>
                        ) : (
                            'Save Changes'
                        )}
                    </button>
                </div>
            </form>
        </div>
    )
}

import { useState, useEffect } from 'react'
import { supabase } from '../lib/supabase'
import ProductCard from '../components/ProductCard'

const CATEGORIES = ['All', 'Books', 'Electronics', 'Clothing', 'Furniture', 'Stationery', 'Sports', 'Other']
const SORT_OPTIONS = [
    { value: 'newest', label: 'Newest First' },
    { value: 'oldest', label: 'Oldest First' },
    { value: 'price_low', label: 'Price: Low → High' },
    { value: 'price_high', label: 'Price: High → Low' },
]

export default function Feed() {
    const [products, setProducts] = useState([])
    const [loading, setLoading] = useState(true)
    const [search, setSearch] = useState('')
    const [searchInput, setSearchInput] = useState('')
    const [category, setCategory] = useState('All')
    const [sort, setSort] = useState('newest')

    useEffect(() => {
        fetchProducts()
    }, [category, sort])

    async function fetchProducts() {
        setLoading(true)
        try {
            let query = supabase
                .from('products')
                .select('*, profiles(full_name, avatar_url, whatsapp_number)')

            if (category !== 'All') {
                query = query.eq('category', category)
            }

            switch (sort) {
                case 'newest':
                    query = query.order('created_at', { ascending: false })
                    break
                case 'oldest':
                    query = query.order('created_at', { ascending: true })
                    break
                case 'price_low':
                    query = query.order('price', { ascending: true })
                    break
                case 'price_high':
                    query = query.order('price', { ascending: false })
                    break
            }

            const { data, error } = await query
            if (error) throw error
            setProducts(data || [])
        } catch (err) {
            console.error('Error fetching products:', err)
        } finally {
            setLoading(false)
        }
    }

    const filtered = products.filter((p) =>
        p.name.toLowerCase().includes(search.toLowerCase()) ||
        p.description?.toLowerCase().includes(search.toLowerCase())
    )

    const handleSearch = (e) => {
        e.preventDefault()
        setSearch(searchInput)
    }

    return (
        <div className="feed-page">

            <div className="feed-controls">
                <form className="search-bar" onSubmit={handleSearch}>
                    <input
                        type="text"
                        placeholder="Search products..."
                        value={searchInput}
                        onChange={(e) => setSearchInput(e.target.value)}
                    />
                    {searchInput && (
                        <button type="button" className="search-clear" onClick={() => { setSearchInput(''); setSearch('') }}>×</button>
                    )}
                    <button type="submit" className="search-btn">
                        <svg className="search-btn-icon" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                            <circle cx="11" cy="11" r="8" /><line x1="21" y1="21" x2="16.65" y2="16.65" />
                        </svg>
                        <span className="search-btn-text">Search</span>
                    </button>
                </form>

                <select
                    className="sort-select"
                    value={sort}
                    onChange={(e) => setSort(e.target.value)}
                >
                    {SORT_OPTIONS.map((opt) => (
                        <option key={opt.value} value={opt.value}>{opt.label}</option>
                    ))}
                </select>
            </div>

            <div className="filters-scroll-row">

                <div className="category-chips">
                    {CATEGORIES.map((cat) => (
                        <button
                            key={cat}
                            className={`chip ${category === cat ? 'chip-active' : ''}`}
                            onClick={() => setCategory(cat)}
                        >
                            {cat}
                        </button>
                    ))}
                </div>
            </div>

            {loading ? (
                <div className="feed-loading">
                    <div className="spinner"></div>
                    <p>Loading listings...</p>
                </div>
            ) : filtered.length === 0 ? (
                <div className="feed-empty">
                    <span className="empty-icon">📦</span>
                    <h3>No items found</h3>
                    <p>{search ? 'Try a different search term' : 'Be the first to list something!'}</p>
                </div>
            ) : (
                <div className="product-grid">
                    {filtered.map((product) => (
                        <ProductCard key={product.id} product={product} />
                    ))}
                </div>
            )}
        </div>
    )
}

import { useState, useEffect } from 'react'
import { useNavigate } from 'react-router-dom'
import { supabase } from '../lib/supabase'
import { useAuth } from '../context/AuthContext'
import ProductCard from '../components/ProductCard'

export default function MyListings() {
    const { user } = useAuth()
    const navigate = useNavigate()
    const [products, setProducts] = useState([])
    const [loading, setLoading] = useState(true)

    useEffect(() => {
        if (user) fetchMyProducts()
    }, [user])

    async function fetchMyProducts() {
        try {
            const { data, error } = await supabase
                .from('products')
                .select('*, profiles(full_name, avatar_url)')
                .eq('user_id', user.id)
                .order('created_at', { ascending: false })

            if (error) throw error
            setProducts(data || [])
        } catch (err) {
            console.error('Error:', err)
        } finally {
            setLoading(false)
        }
    }

    return (
        <div className="my-listings-page">
            <div className="page-header">
                <h1>My Listings</h1>
                <p>Manage your products</p>
                <p className="ux-hint" style={{ marginTop: '12px', fontSize: '0.85rem', color: 'var(--accent)', fontWeight: '500', display: 'flex', alignItems: 'center', gap: '6px' }}>
                    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                        <circle cx="12" cy="12" r="10" /><line x1="12" y1="16" x2="12" y2="12" /><line x1="12" y1="8" x2="12.01" y2="8" />
                    </svg>
                    Click on any listing below to edit or delete it
                </p>
            </div>

            {loading ? (
                <div className="feed-loading">
                    <div className="spinner"></div>
                    <p>Loading your listings...</p>
                </div>
            ) : products.length === 0 ? (
                <div className="feed-empty">
                    <span className="empty-icon">📋</span>
                    <h3>No listings yet</h3>
                    <p>Start selling to your college community!</p>
                    <button className="btn btn-primary" onClick={() => navigate('/sell')}>
                        Create Your First Listing
                    </button>
                </div>
            ) : (
                <div className="product-grid">
                    {products.map((product) => (
                        <ProductCard key={product.id} product={product} />
                    ))}
                </div>
            )}
        </div>
    )
}

import { useState, useEffect } from 'react'
import { useParams, useNavigate } from 'react-router-dom'
import { supabase } from '../lib/supabase'
import { useAuth } from '../context/AuthContext'

function timeAgo(dateStr) {
    const now = new Date()
    const date = new Date(dateStr)
    const seconds = Math.floor((now - date) / 1000)
    if (seconds < 60) return 'Just now'
    const minutes = Math.floor(seconds / 60)
    if (minutes < 60) return `${minutes} minutes ago`
    const hours = Math.floor(minutes / 60)
    if (hours < 24) return `${hours} hours ago`
    const days = Math.floor(hours / 24)
    if (days < 7) return `${days} days ago`
    return date.toLocaleDateString()
}

export default function ProductDetail() {
    const { id } = useParams()
    const navigate = useNavigate()
    const { user } = useAuth()
    const [product, setProduct] = useState(null)
    const [loading, setLoading] = useState(true)
    const [activeImage, setActiveImage] = useState(0)
    const [deleting, setDeleting] = useState(false)

    useEffect(() => {
        fetchProduct()
    }, [id])

    async function fetchProduct() {
        try {
            const { data, error } = await supabase
                .from('products')
                .select('*, profiles(full_name, avatar_url, whatsapp_number)')
                .eq('id', id)
                .single()

            if (error) throw error
            setProduct(data)
        } catch (err) {
            console.error('Error:', err)
        } finally {
            setLoading(false)
        }
    }

    async function handleDelete() {
        if (!confirm('Are you sure you want to delete this listing?')) return
        setDeleting(true)
        try {
            if (product.images && product.images.length > 0) {
                const pathsToRemove = product.images.map(url => {
                    const parts = url.split('product-images/')
                    return parts.length > 1 ? parts[1] : null
                }).filter(Boolean)

                if (pathsToRemove.length > 0) {
                    const { error: storageError } = await supabase.storage
                        .from('product-images')
                        .remove(pathsToRemove)
                    if (storageError) console.error('Error removing images:', storageError)
                }
            }

            const { error } = await supabase.from('products').delete().eq('id', id)
            if (error) throw error
            navigate('/')
        } catch (err) {
            console.error('Error deleting:', err)
            alert('Failed to delete listing')
        } finally {
            setDeleting(false)
        }
    }

    function openWhatsApp() {
        let phone = product.profiles?.whatsapp_number?.replace(/[^0-9]/g, '')
        if (!phone) {
            alert('Seller has not added their WhatsApp number yet.')
            return
        }

        // Ensure phone starts with 91
        if (!phone.startsWith('91')) {
            phone = '91' + phone;
        }

        const message = encodeURIComponent(
            `Hi! I'm interested in "${product.name}" (ID: ${product.id}) listed on BVEC Shoppers. Is it still available?`
        )
        window.open(`https://wa.me/${phone}?text=${message}`, '_blank')
    }

    if (loading) {
        return (
            <div className="loading-screen">
                <div className="spinner"></div>
                <p>Loading product...</p>
            </div>
        )
    }

    if (!product) {
        return (
            <div className="feed-empty">
                <span className="empty-icon">🔍</span>
                <h3>Product not found</h3>
                <button className="btn btn-primary" onClick={() => navigate('/')}>Back to Feed</button>
            </div>
        )
    }

    const isOwner = user?.id === product.user_id

    return (
        <div className="product-detail-page">
            <button className="btn-back" onClick={() => navigate(-1)}>
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                    <polyline points="15 18 9 12 15 6" />
                </svg>
                Back
            </button>

            <div className="product-detail-layout">
                <div className="product-images-section">
                    {product.images?.length > 0 ? (
                        <>
                            <div className="product-main-image">
                                <img src={product.images[activeImage]} alt={product.name} />
                            </div>
                            {product.images.length > 1 && (
                                <div className="product-thumbnails">
                                    {product.images.map((img, i) => (
                                        <button
                                            key={i}
                                            className={`thumbnail ${i === activeImage ? 'active' : ''}`}
                                            onClick={() => setActiveImage(i)}
                                        >
                                            <img src={img} alt={`${product.name} ${i + 1}`} />
                                        </button>
                                    ))}
                                </div>
                            )}
                        </>
                    ) : (
                        <div className="product-no-image">
                            <svg width="64" height="64" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1" strokeLinecap="round" strokeLinejoin="round" opacity="0.3">
                                <rect x="3" y="3" width="18" height="18" rx="2" ry="2" /><circle cx="8.5" cy="8.5" r="1.5" /><polyline points="21 15 16 10 5 21" />
                            </svg>
                            <p>No photos available</p>
                        </div>
                    )}
                </div>

                <div className="product-info-section">
                    <div className="product-info-header">
                        {product.category && (
                            <span className="product-category-badge">{product.category}</span>
                        )}
                        <h1 className="product-title">{product.name}</h1>
                        <p className="product-price">₹{Number(product.price).toLocaleString('en-IN')}</p>
                    </div>

                    {product.description && (
                        <div className="product-description">
                            <h3>Description</h3>
                            <p>{product.description}</p>
                        </div>
                    )}

                    <div className="product-seller-card">
                        <img
                            src={product.profiles?.avatar_url || `https://ui-avatars.com/api/?name=${product.profiles?.full_name || 'U'}&background=6c63ff&color=fff`}
                            alt=""
                            className="seller-avatar"
                        />
                        <div className="seller-info">
                            <span className="seller-name">{product.profiles?.full_name || 'Anonymous'}</span>
                            <span className="seller-time">Listed {timeAgo(product.created_at)}</span>
                        </div>
                    </div>

                    <div className="product-actions">
                        {isOwner ? (
                            <>
                                <button
                                    className="btn btn-secondary btn-lg"
                                    onClick={() => navigate(`/edit/${product.id}`)}
                                >
                                    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                        <path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"></path>
                                        <path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"></path>
                                    </svg>
                                    Edit
                                </button>
                                <button
                                    className="btn btn-danger btn-lg"
                                    onClick={handleDelete}
                                    disabled={deleting}
                                >
                                    {deleting ? 'Deleting...' : 'Delete'}
                                </button>
                            </>
                        ) : (
                            <button className="btn btn-whatsapp btn-lg" onClick={openWhatsApp}>
                                <svg width="22" height="22" viewBox="0 0 24 24" fill="currentColor">
                                    <path d="M17.472 14.382c-.297-.149-1.758-.867-2.03-.967-.273-.099-.471-.148-.67.15-.197.297-.767.966-.94 1.164-.173.199-.347.223-.644.075-.297-.15-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.298-.347.446-.52.149-.174.198-.298.298-.497.099-.198.05-.371-.025-.52-.075-.149-.669-1.612-.916-2.207-.242-.579-.487-.5-.669-.51-.173-.008-.371-.01-.57-.01-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.694.625.712.227 1.36.195 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.694.248-1.289.173-1.413-.074-.124-.272-.198-.57-.347m-5.421 7.403h-.004a9.87 9.87 0 01-5.031-1.378l-.361-.214-3.741.982.998-3.648-.235-.374a9.86 9.86 0 01-1.51-5.26c.001-5.45 4.436-9.884 9.888-9.884 2.64 0 5.122 1.03 6.988 2.898a9.825 9.825 0 012.893 6.994c-.003 5.45-4.437 9.884-9.885 9.884m8.413-18.297A11.815 11.815 0 0012.05 0C5.495 0 .16 5.335.157 11.892c0 2.096.547 4.142 1.588 5.945L.057 24l6.305-1.654a11.882 11.882 0 005.683 1.448h.005c6.554 0 11.89-5.335 11.893-11.893a11.821 11.821 0 00-3.48-8.413z" />
                                </svg>
                                Contact on WhatsApp
                            </button>
                        )}
                    </div>

                    <p className="product-id">ID: {product.id}</p>
                </div>
            </div>
        </div>
    )
}
